#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

inline int maximum(int a, int b, int c) {
    int k = (a <= b) ? b : a;
    return (k <= c) ? c : k;
}

__kernel void nw_kernel1(__global int *reference,
                         __global int *input_itemsets,
                         __global int *output_itemsets,
                         __local int *input_itemsets_l,
                         __local int *reference_l,
                         int max_cols,
                         int penalty,
                         int blk,
                         int block_width,
                         int worksize,
                         int offset_r,
                         int offset_c)
{
    int tx = get_local_id(0);
    int b_index_x = get_group_id(0);
    int b_index_y = blk - 1 - b_index_x;

    if (tx < BLOCK_SIZE) {
        int ref_row = b_index_y * BLOCK_SIZE + tx + 1 + offset_r;
        int ref_col = b_index_x * BLOCK_SIZE + 1 + offset_c;
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            reference_l[tx * BLOCK_SIZE + j] =
                reference[max_cols * ref_row + ref_col + j];
        }

        int in_row = b_index_y * BLOCK_SIZE + tx + offset_r;
        int in_col = b_index_x * BLOCK_SIZE + offset_c;
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[tx * (BLOCK_SIZE + 1) + j] =
                input_itemsets[max_cols * in_row + in_col + j];
        }
    }

    if (tx == 0) {
        int in_row = b_index_y * BLOCK_SIZE + BLOCK_SIZE + offset_r;
        int in_col = b_index_x * BLOCK_SIZE + offset_c;
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[BLOCK_SIZE * (BLOCK_SIZE + 1) + j] =
                input_itemsets[max_cols * in_row + in_col + j];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int m = 0; m < BLOCK_SIZE; ++m) {
        if (tx <= m) {
            int i = tx + 1;
            int j = m - tx + 1;
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                maximum(input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + (j - 1)] +
                            reference_l[(i - 1) * BLOCK_SIZE + (j - 1)],
                        input_itemsets_l[i * (BLOCK_SIZE + 1) + (j - 1)] - penalty,
                        input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    for (int m = BLOCK_SIZE - 2; m >= 0; --m) {
        if (tx <= m) {
            int i = BLOCK_SIZE - m + tx;
            int j = BLOCK_SIZE - tx;
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                maximum(input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + (j - 1)] +
                            reference_l[(i - 1) * BLOCK_SIZE + (j - 1)],
                        input_itemsets_l[i * (BLOCK_SIZE + 1) + (j - 1)] - penalty,
                        input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (tx < BLOCK_SIZE) {
        int out_row = b_index_y * BLOCK_SIZE + tx + 1 + offset_r;
        int out_col = b_index_x * BLOCK_SIZE + 1 + offset_c;
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            int v = input_itemsets_l[(tx + 1) * (BLOCK_SIZE + 1) + (j + 1)];
            input_itemsets[max_cols * out_row + out_col + j] = v;
        }
    }
}

